## Task Description

Implement toolchain verification and automatic installation on the worker agent. Before executing a compilation command, the worker ensures the required toolchain is available, installing it via rustup if necessary.

## Design

### Flow
```
1. Worker receives ExecutionRequest with toolchain
2. Check if toolchain is already available
3. If not available, install via rustup
4. Execute command with rustup run <toolchain> <command>
5. Cache toolchain availability for future requests
```

### Implementation
```rust
// In rch-wkr/src/toolchain.rs (new file)

use std::collections::HashSet;
use std::sync::RwLock;
use tokio::process::Command;

/// Cache of available toolchains on this worker
pub struct ToolchainCache {
    available: RwLock<HashSet<String>>,
}

impl ToolchainCache {
    pub fn new() -> Self {
        Self {
            available: RwLock::new(HashSet::new()),
        }
    }

    /// Check if a toolchain is known to be available
    pub fn is_available(&self, toolchain: &str) -> bool {
        self.available.read().unwrap().contains(toolchain)
    }

    /// Mark a toolchain as available
    pub fn mark_available(&self, toolchain: &str) {
        self.available.write().unwrap().insert(toolchain.to_string());
    }

    /// Refresh cache by querying rustup
    pub async fn refresh(&self) -> Result<(), ToolchainError> {
        let output = Command::new("rustup")
            .args(["toolchain", "list"])
            .output()
            .await?;

        let stdout = String::from_utf8_lossy(&output.stdout);
        let mut available = self.available.write().unwrap();
        available.clear();

        for line in stdout.lines() {
            // Parse: "nightly-2024-01-15-x86_64-unknown-linux-gnu (default)"
            let toolchain = line
                .split_whitespace()
                .next()
                .unwrap_or("")
                .trim();
            if !toolchain.is_empty() {
                // Store both full and short forms
                available.insert(toolchain.to_string());
                // Also store without target triple
                if let Some(short) = strip_target_triple(toolchain) {
                    available.insert(short);
                }
            }
        }

        Ok(())
    }
}

fn strip_target_triple(toolchain: &str) -> Option<String> {
    // "nightly-2024-01-15-x86_64-unknown-linux-gnu" -> "nightly-2024-01-15"
    let parts: Vec<&str> = toolchain.split('-').collect();
    if parts.len() >= 4 && parts.last()?.contains("gnu") || parts.last()?.contains("msvc") {
        // Find where target triple starts (usually after date or channel)
        // This is heuristic - target triples have architecture patterns
        Some(parts[..3].join("-"))  // Keep first 3 parts
    } else {
        None
    }
}

/// Ensure a toolchain is available, installing if necessary
pub async fn ensure_toolchain(
    toolchain: &ToolchainInfo,
    cache: &ToolchainCache,
) -> Result<(), ToolchainError> {
    let tc_string = toolchain.rustup_toolchain();

    // Check cache first
    if cache.is_available(&tc_string) {
        tracing::debug!(toolchain = %tc_string, "Toolchain in cache");
        return Ok(());
    }

    // Check if actually installed (cache miss or cold start)
    if check_toolchain_installed(&tc_string).await? {
        cache.mark_available(&tc_string);
        return Ok(());
    }

    // Install the toolchain
    tracing::info!(toolchain = %tc_string, "Installing toolchain");
    install_toolchain(&tc_string).await?;
    cache.mark_available(&tc_string);

    Ok(())
}

async fn check_toolchain_installed(toolchain: &str) -> Result<bool, ToolchainError> {
    let output = Command::new("rustup")
        .args(["run", toolchain, "rustc", "--version"])
        .output()
        .await?;

    Ok(output.status.success())
}

async fn install_toolchain(toolchain: &str) -> Result<(), ToolchainError> {
    let output = Command::new("rustup")
        .args(["toolchain", "install", toolchain, "--profile", "minimal"])
        .output()
        .await?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        return Err(ToolchainError::InstallFailed {
            toolchain: toolchain.to_string(),
            error: stderr.to_string(),
        });
    }

    tracing::info!(toolchain = %toolchain, "Toolchain installed successfully");
    Ok(())
}

#[derive(Debug, thiserror::Error)]
pub enum ToolchainError {
    #[error("IO error: {0}")]
    Io(#[from] std::io::Error),

    #[error("Failed to install toolchain {toolchain}: {error}")]
    InstallFailed {
        toolchain: String,
        error: String,
    },

    #[error("Toolchain {0} not available and cannot be installed")]
    NotAvailable(String),
}
```

### Integration with Executor
```rust
// In rch-wkr/src/executor.rs

impl Executor {
    pub async fn execute(
        &self,
        request: ExecutionRequest,
    ) -> Result<ExecutionResult, ExecutorError> {
        // Ensure toolchain if specified
        if let Some(ref toolchain) = request.toolchain {
            if let Err(e) = ensure_toolchain(toolchain, &self.toolchain_cache).await {
                tracing::warn!(
                    error = %e,
                    "Failed to ensure toolchain, attempting execution anyway"
                );
                // Don't fail here - let compilation try and fail with better error
            }
        }

        // Wrap command with rustup run if toolchain specified
        let command = match &request.toolchain {
            Some(tc) => format!("rustup run {} {}", tc.rustup_toolchain(), request.command),
            None => request.command.clone(),
        };

        // Execute
        self.run_command(&command, &request.working_dir, &request.env).await
    }
}
```

