### Implementation
Use `clap_complete` crate:
```rust
use clap_complete::{generate, shells::*};

fn print_completions<G: Generator>(gen: G, cmd: &mut Command) {
    generate(gen, cmd, "rch", &mut std::io::stdout());
}
